/**
 * Main Page Builder Interface
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

'use client';

import React, { useState, useCallback } from 'react';
import { DndContext, DragEndEvent, DragOverlay, DragStartEvent } from '@dnd-kit/core';
import { SortableContext, verticalListSortingStrategy } from '@dnd-kit/sortable';
import { Canvas } from './Canvas';
import { SectionLibrary } from './SectionLibrary';
import { PropertyPanel } from './PropertyPanel';
import { Toolbar } from './Toolbar';
import { PreviewModes } from './PreviewModes';
import { SectionConfig } from '@/lib/page-builder/section-schemas';
import { SECTION_TEMPLATES } from '@/lib/page-builder/section-registry';

interface PageBuilderProps {
  pageId: string;
  initialSections?: SectionConfig[];
  onSave?: (sections: SectionConfig[]) => Promise<void>;
}

export function PageBuilder({ pageId, initialSections = [], onSave }: PageBuilderProps) {
  const [sections, setSections] = useState<SectionConfig[]>(Array.isArray(initialSections) ? initialSections : []);
  const [selectedSectionId, setSelectedSectionId] = useState<string | null>(null);
  const [previewMode, setPreviewMode] = useState<'desktop' | 'tablet' | 'mobile'>('desktop');
  const [isPreviewMode, setIsPreviewMode] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [draggedSection, setDraggedSection] = useState<SectionConfig | null>(null);

  const selectedSection = Array.isArray(sections) ? sections.find(s => s.id === selectedSectionId) : null;

  // Add new section from library
  const handleAddSection = useCallback((templateType: string) => {
    const template = SECTION_TEMPLATES.find(t => t.type === templateType);
    if (!template) return;

    const newSection: SectionConfig = {
      ...template.defaultData,
      id: `section-${Date.now()}`,
      order: sections.length,
    };

    setSections(prev => [...prev, newSection]);
    setSelectedSectionId(newSection.id);
  }, [sections.length]);

  // Update section configuration
  const handleUpdateSection = useCallback((sectionId: string, updates: Partial<SectionConfig>) => {
    setSections(prev => prev.map(section => 
      section.id === sectionId 
        ? { ...section, ...updates } as SectionConfig
        : section
    ));
  }, []);

  // Delete section
  const handleDeleteSection = useCallback((sectionId: string) => {
    setSections(prev => prev.filter(s => s.id !== sectionId));
    if (selectedSectionId === sectionId) {
      setSelectedSectionId(null);
    }
  }, [selectedSectionId]);

  // Duplicate section
  const handleDuplicateSection = useCallback((sectionId: string) => {
    const section = sections.find(s => s.id === sectionId);
    if (!section) return;

    const duplicatedSection: SectionConfig = {
      ...section,
      id: `section-${Date.now()}`,
      order: section.order + 1,
    };

    setSections(prev => {
      const newSections = [...prev];
      const insertIndex = newSections.findIndex(s => s.id === sectionId) + 1;
      newSections.splice(insertIndex, 0, duplicatedSection);
      
      // Update order for sections after the duplicated one
      return newSections.map((s, index) => ({ ...s, order: index }));
    });
  }, [sections]);

  // Handle drag start
  const handleDragStart = (event: DragStartEvent) => {
    const { active } = event;
    const section = sections.find(s => s.id === active.id);
    setDraggedSection(section || null);
  };

  // Handle drag end
  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    setDraggedSection(null);

    if (!over || active.id === over.id) return;

    setSections(prev => {
      const oldIndex = prev.findIndex(s => s.id === active.id);
      const newIndex = prev.findIndex(s => s.id === over.id);

      if (oldIndex === -1 || newIndex === -1) return prev;

      const newSections = [...prev];
      const [movedSection] = newSections.splice(oldIndex, 1);
      newSections.splice(newIndex, 0, movedSection);

      // Update order
      return newSections.map((section, index) => ({
        ...section,
        order: index,
      }));
    });
  };

  // Save page
  const handleSave = async () => {
    if (!onSave) return;
    
    setIsSaving(true);
    try {
      await onSave(sections);
    } catch (error) {
      console.error('Failed to save page:', error);
    } finally {
      setIsSaving(false);
    }
  };

  return (
    <div className="h-screen flex flex-col bg-gray-50 dark:bg-gray-900">
      {/* Toolbar */}
      <Toolbar
        onSave={handleSave}
        isSaving={isSaving}
        isPreviewMode={isPreviewMode}
        onTogglePreview={() => setIsPreviewMode(!isPreviewMode)}
        previewMode={previewMode}
        onPreviewModeChange={setPreviewMode}
      />

      <div className="flex-1 flex overflow-hidden">
        {!isPreviewMode && (
          <>
            {/* Section Library */}
            <SectionLibrary onAddSection={handleAddSection} />

            {/* Main Canvas */}
            <div className="flex-1 flex flex-col">
              <PreviewModes 
                mode={previewMode} 
                onModeChange={setPreviewMode} 
              />
              
              <DndContext onDragStart={handleDragStart} onDragEnd={handleDragEnd}>
                <SortableContext 
                  items={sections.map(s => s.id)} 
                  strategy={verticalListSortingStrategy}
                >
                  <Canvas
                    sections={sections}
                    selectedSectionId={selectedSectionId}
                    onSectionSelect={setSelectedSectionId}
                    onSectionDelete={handleDeleteSection}
                    onSectionDuplicate={handleDuplicateSection}
                    previewMode={previewMode}
                  />
                </SortableContext>
                
                <DragOverlay>
                  {draggedSection && (
                    <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg p-4 opacity-90">
                      <p className="font-medium">{draggedSection.type}</p>
                    </div>
                  )}
                </DragOverlay>
              </DndContext>
            </div>

            {/* Property Panel */}
            {selectedSection && (
              <PropertyPanel
                section={selectedSection}
                onUpdate={(updates) => handleUpdateSection(selectedSection.id, updates)}
                onClose={() => setSelectedSectionId(null)}
              />
            )}
          </>
        )}

        {/* Preview Mode */}
        {isPreviewMode && (
          <div className="flex-1 overflow-auto">
            <Canvas
              sections={sections}
              selectedSectionId={null}
              onSectionSelect={() => {}}
              onSectionDelete={() => {}}
              onSectionDuplicate={() => {}}
              previewMode={previewMode}
              isPreview={true}
            />
          </div>
        )}
      </div>
    </div>
  );
}